if (! function_exists('color_palette_generator')) {
    function color_palette_generator($seed_color, $scheme = null, $count = null)
    {
        $seed = ltrim(trim($seed_color), '#');
        $scheme = $scheme ?? 'complementary';
        $count = $count ?? 5;

        // Validate seed
        if (!preg_match('/^[0-9a-fA-F]{6}$/', $seed)) {
            return json_encode(['error' => 'Invalid hex color. Use format: ff3366 or #ff3366']);
        }

        $allowedSchemes = ['complementary', 'triadic', 'analogous', 'monochromatic', 'split_complementary', 'tetradic'];
        if (!in_array($scheme, $allowedSchemes)) {
            return json_encode(['error' => 'Invalid scheme. Must be: ' . implode(', ', $allowedSchemes)]);
        }

        // Parse RGB
        $r = hexdec(substr($seed, 0, 2));
        $g = hexdec(substr($seed, 2, 2));
        $b = hexdec(substr($seed, 4, 2));

        // RGB to HSL
        $rf = $r / 255; $gf = $g / 255; $bf = $b / 255;
        $max = max($rf, $gf, $bf); $min = min($rf, $gf, $bf);
        $delta = $max - $min;

        $h = 0; $s = 0; $l = ($max + $min) / 2;
        if ($delta > 0.0001) {
            $s = $l <= 0.5 ? $delta / ($max + $min) : $delta / (2 - $max - $min);
            if ($max === $rf) $h = 60 * fmod(($gf - $bf) / $delta, 6);
            elseif ($max === $gf) $h = 60 * (($bf - $rf) / $delta + 2);
            else $h = 60 * (($rf - $gf) / $delta + 4);
            if ($h < 0) $h += 360;
        }

        // Helper: HSL to hex
        $hslToHex = function($hue, $sat, $light) {
            $c = (1 - abs(2 * $light - 1)) * $sat;
            $x = $c * (1 - abs(fmod($hue / 60, 2) - 1));
            $m = $light - $c / 2;
            if ($hue < 60) { $r1 = $c; $g1 = $x; $b1 = 0; }
            elseif ($hue < 120) { $r1 = $x; $g1 = $c; $b1 = 0; }
            elseif ($hue < 180) { $r1 = 0; $g1 = $c; $b1 = $x; }
            elseif ($hue < 240) { $r1 = 0; $g1 = $x; $b1 = $c; }
            elseif ($hue < 300) { $r1 = $x; $g1 = 0; $b1 = $c; }
            else { $r1 = $c; $g1 = 0; $b1 = $x; }
            $r = (int)round(($r1 + $m) * 255);
            $G = (int)round(($g1 + $m) * 255);
            $b2 = (int)round(($b1 + $m) * 255);
            return '#' . str_pad(dechex($r), 2, '0', STR_PAD_LEFT) . str_pad(dechex($G), 2, '0', STR_PAD_LEFT) . str_pad(dechex($b2), 2, '0', STR_PAD_LEFT);
        };

        // Clamp hue to 0-360
        $h = fmod($h, 360); if ($h < 0) $h += 360;

        $palette = [];
        switch ($scheme) {
            case 'complementary':
                $palette[] = $hslToHex($h, $s, $l);
                $palette[] = $hslToHex(fmod($h + 180, 360), $s, $l);
                // Add two more intermediate colors for a 4-color palette
                $palette[] = $hslToHex(fmod($h + 30, 360), $s * 0.8, $l + 0.1);
                $palette[] = $hslToHex(fmod($h + 210, 360), $s * 0.8, $l - 0.1);
                break;

            case 'triadic':
                $palette[] = $hslToHex($h, $s, $l);
                $palette[] = $hslToHex(fmod($h + 120, 360), $s, $l);
                $palette[] = $hslToHex(fmod($h + 240, 360), $s, $l);
                break;

            case 'analogous':
                $palette[] = $hslToHex(fmod($h - 30, 360), $s, $l);
                $palette[] = $hslToHex($h, $s, $l);
                $palette[] = $hslToHex(fmod($h + 30, 360), $s, $l);
                $palette[] = $hslToHex(fmod($h + 60, 360), $s * 0.85, $l * 0.9);
                $palette[] = $hslToHex(fmod($h - 60, 360), $s * 0.85, $l * 1.1);
                break;

            case 'split_complementary':
                $palette[] = $hslToHex($h, $s, $l);
                $palette[] = $hslToHex(fmod($h + 150, 360), $s, $l);
                $palette[] = $hslToHex(fmod($h + 210, 360), $s, $l);
                break;

            case 'tetradic':
                $palette[] = $hslToHex($h, $s, $l);
                $palette[] = $hslToHex(fmod($h + 90, 360), $s, $l);
                $palette[] = $hslToHex(fmod($h + 180, 360), $s, $l);
                $palette[] = $hslToHex(fmod($h + 270, 360), $s, $l);
                break;

            case 'monochromatic':
                $lightnessStep = 0.15;
                $start = max(0.1, $l - ($count - 1) * $lightnessStep / 2);
                for ($i = 0; $i < $count; $i++) {
                    $li = min(0.9, $start + $i * $lightnessStep);
                    $si = $s * (1 - abs($l - $li) * 0.5); // slight saturation variation
                    $palette[] = $hslToHex($h, max(0, min(1, $si)), max(0, min(1, $li)));
                }
                break;
        }

        return json_encode([
            'seed_color' => '#' . $seed,
            'scheme' => $scheme,
            'palette' => $palette,
            'description' => match($scheme) {
                'complementary' => 'Colors opposite each other on the color wheel — high contrast, vibrant',
                'triadic' => 'Three evenly-spaced colors — balanced, rich harmony',
                'analogous' => 'Adjacent colors on the wheel — serene, harmonious',
                'split_complementary' => 'Base color plus two adjacent to its complement — versatile, high contrast without tension',
                'tetradic' => 'Two complementary pairs — rich, complex harmony',
                'monochromatic' => 'Single hue in varying lightness — cohesive, elegant',
                default => ''
            },
            'count' => count($palette),
        ]);
    }
}
